package com.babidndn.payment; import jakarta.persistence.*;import java.time.LocalDateTime;
@Entity public class Payment { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String method; private int amount; @Enumerated(EnumType.STRING) private PaymentStatus status; private LocalDateTime paidAt; private String pgTransactionId; protected Payment(){} public Payment(String method,int amount,PaymentStatus status,String pgTransactionId){this.method=method;this.amount=amount;this.status=status;this.pgTransactionId=pgTransactionId;this.paidAt=LocalDateTime.now();} public Long getId(){return id;} public String getMethod(){return method;} public int getAmount(){return amount;} public PaymentStatus getStatus(){return status;} public LocalDateTime getPaidAt(){return paidAt;} public String getPgTransactionId(){return pgTransactionId;} }
